solutions.cpp:
#include <numeric>

#include <iostream>
using namespace std;

class Solution {
public:
    int countGoodNumbers(int n) {
        const int MOD = 1e9 + 7;
        long long res = 1;
        for (int i = 0; i < n / 2; i++) {
            res = (res * 5) % MOD;
        }
        for (int i = 0; i < n - n / 2; i++) {
            res = (res * 4) % MOD;
        }
        return res;
    }
};

int main() {
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    int ans = sol.countGoodNumbers(n);
    cout << ans << endl;
    return 0;
}
